@page "/category/{CategoryName}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipes is not null && recipes.Count > 0)
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>@recipe.AverageRating.ToString("F1") ★ (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <p>No recipes found in this category.</p>
}

<a href="/" class="btn btn-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeShare.Models.Recipe>? recipes;

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (recipe is not null)
{
    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: <a href="category/@recipe.Category">@recipe.Category</a></p>

    <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" RatingCount="recipe.RatingCount" />

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@step.TrimStart("0123456789. ".ToCharArray())</li>
        }
    </ol>

    <a href="category/@recipe.Category" class="btn btn-secondary mt-3">← Back to @recipe.Category</a>
}
else
{
    <p>Recipe not found.</p>
    <a href="/" class="btn btn-secondary">← Back to Home</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="my-3">
    <strong>Rating: </strong>
    @if (RatingCount > 0)
    {
        <span>@CurrentAverage.ToString("F1") ★ (@RatingCount ratings)</span>
    }
    else
    {
        <span>No ratings yet</span>
    }
    <div class="mt-2">
        <span>Rate this recipe: </span>
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button class="btn btn-sm @(star <= selectedStars ? "btn-warning" : "btn-outline-secondary")"
                    @onclick="() => SubmitRating(star)"
                    title="@star stars">
                ★
            </button>
        }
        @if (rated)
        {
            <span class="text-success ms-2">Thanks for rating!</span>
        }
    </div>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int selectedStars;
    private bool rated;

    private void SubmitRating(int stars)
    {
        selectedStars = stars;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        rated = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (!submitted)
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="model.Title" class="form-control" />
            <ValidationMessage For="() => model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Breakfast">Breakfast</option>
                <option value="Lunch">Lunch</option>
                <option value="Dinner">Dinner</option>
                <option value="Desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="model.Ingredients" class="form-control" rows="6" />
            <ValidationMessage For="() => model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="model.Steps" class="form-control" rows="6" />
            <ValidationMessage For="() => model.Steps" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}
else
{
    <div class="alert alert-success">
        <h4>Recipe submitted!</h4>
        <p>Your recipe "<strong>@model.Title</strong>" has been added.</p>
        <a href="category/@model.Category" class="btn btn-primary">View in @model.Category</a>
        <button class="btn btn-secondary ms-2" @onclick="Reset">Submit Another</button>
    </div>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(model.Title, model.Category, model.Ingredients, model.Steps);
        submitted = true;
    }

    private void Reset()
    {
        model = new();
        submitted = false;
    }
}

